SECURITY_TABLE = {
    80: {'rsa': 1024, 'ecc': 160},
    112: {'rsa': 2048, 'ecc': 224},
    128: {'rsa': 3072, 'ecc': 256},
    192: {'rsa': 7680, 'ecc': 384},
    256: {'rsa': 15360, 'ecc': 512}
}

def rsa_to_security_bits(rsa_bits: int) -> int:
    for sec, sizes in SECURITY_TABLE.items():
        if sizes['rsa'] >= rsa_bits:
            return sec
    return 256

def ecc_to_security_bits(ecc_bits: int) -> int:
    return ecc_bits // 2

def equivalent_ecc_for_rsa(rsa_bits: int) -> int:
    sec = rsa_to_security_bits(rsa_bits)
    return SECURITY_TABLE.get(sec, {}).get('ecc', 512)

def compare_key_sizes(security_bits: int) -> dict:
    if security_bits in SECURITY_TABLE:
        return SECURITY_TABLE[security_bits]
    return {'rsa': 'unknown', 'ecc': security_bits * 2}
